function Modbus_Read_Coils
  (Handle        : C_Master_Handle;
   Slave         : unsigned_char;
   Start_Address : unsigned_short;
   Quantity      : unsigned_short;
   Values        : access unsigned_char;
   Timeout_Ms    : int) return C_Status

function Modbus_Read_Discrete_Inputs
  (Handle        : C_Master_Handle;
   Slave         : unsigned_char;
   Start_Address : unsigned_short;
